const watchlistItems = $('Get Watchlist').all();
const fetchNode = $('Fetch Live Prices').first().json;
const html = fetchNode.data || fetchNode.body || "";

if (!html) {
  return [];
}

const watchlist = watchlistItems.map(item => item.json);
if (watchlist.length === 0) {
  return []; // No pending stocks to monitor
}

// Find the table by ID
const tableRegex = /<table[^>]*id=["']headFixed["'][^>]*>([\s\S]*?)<\/table>/i;
const tableMatch = html.match(tableRegex);
if (!tableMatch) {
  return [];
}

const tableContent = tableMatch[1];
const tbodyRegex = /<tbody[^>]*>([\s\S]*?)<\/tbody>/i;
const tbodyMatch = tableContent.match(tbodyRegex);
const bodyContent = tbodyMatch ? tbodyMatch[1] : tableContent;

const rowRegex = /<tr[^>]*>([\s\S]*?)<\/tr>/gi;
let rowMatch;
const stocks = {};

const cleanNum = (str) => {
  const val = parseFloat(str.replace(/,/g, ''));
  return isNaN(val) ? 0 : val;
};

while ((rowMatch = rowRegex.exec(bodyContent)) !== null) {
  const rowHtml = rowMatch[1];
  if (rowHtml.includes('<th')) continue;

  const cellRegex = /<td[^>]*>([\s\S]*?)<\/td>/gi;
  let cellMatch;
  const cells = [];
  while ((cellMatch = cellRegex.exec(rowHtml)) !== null) {
    cells.push(cellMatch[1].replace(/<[^>]*>/g, '').trim());
  }

  if (cells.length >= 18) {
    const symbol = cells[1].toUpperCase();
    stocks[symbol] = {
      symbol: symbol,
      open: cleanNum(cells[3]),
      high: cleanNum(cells[4]),
      low: cleanNum(cells[5]),
      close: cleanNum(cells[6]),
      ltp: cleanNum(cells[7]),
      changePercent: cleanNum(cells[17]),
      volume: cleanNum(cells[11]),
      turnover: cleanNum(cells[13]),
      diff: cleanNum(cells[15])
    };
  }
}

const alerts = [];
for (const watch of watchlist) {
  const symbol = watch.symbol.toUpperCase();
  const stock = stocks[symbol];
  if (stock) {
    let triggered = false;
    let triggerType = "";
    let triggerTarget = 0;

    // Check Take Profit (Target Sell Price)
    if (watch.targetSellPrice && stock.ltp >= watch.targetSellPrice) {
      triggered = true;
      triggerType = "Take Profit 📈";
      triggerTarget = watch.targetSellPrice;
    }
    // Check Stop Loss (Target Loss Price)
    else if (watch.targetLossPrice && stock.ltp <= watch.targetLossPrice) {
      triggered = true;
      triggerType = "Stop Loss 📉";
      triggerTarget = watch.targetLossPrice;
    }

    if (triggered) {
      alerts.push({
        "_id": watch._id || watch.id,
        "symbol": symbol,
        "triggerType": triggerType,
        "triggerTarget": triggerTarget,
        "targetSellPrice": watch.targetSellPrice || null,
        "targetLossPrice": watch.targetLossPrice || null,
        "currentPrice": stock.ltp,
        "open": stock.open,
        "high": stock.high,
        "low": stock.low,
        "volume": stock.volume,
        "changePercent": stock.changePercent,
        "turnover": stock.turnover,
        "diff": stock.diff
      });
    }
  }
}

return alerts.map(alert => ({ json: alert }));

const items = $input.all();
return items.map((item, index) => {
  const geminiText = item.json.candidates[0].content.parts[0].text;
  const stock = $('Scrape and Match Targets').all()[index].json;
  return {
    json: {
      _id: stock._id,
      symbol: stock.symbol,
      triggerType: stock.triggerType,
      triggerTarget: stock.triggerTarget,
      targetSellPrice: stock.targetSellPrice,
      targetLossPrice: stock.targetLossPrice,
      triggerPrice: stock.currentPrice,
      recommendation: geminiText.trim(),
      timestamp: new Date().toISOString(),
      status: "triggered",
      triggeredAt: new Date().toISOString()
    }
  };
});
